try{_toolBlastRows=JSON.parse(localStorage.getItem('ajw_tools_blast_rows')||'[]')}catch(e){_toolBlastRows=[]}
  try{_toolBlastTemplate=localStorage.getItem('ajw_tools_blast_template')||''}catch(e){_toolBlastTemplate=''}
try{_toolBlastHistory=JSON.parse(localStorage.getItem('ajw_tools_blast_history')||'[]')}catch(e){_toolBlastHistory=[]}
