function _toolsGetAgentCorePrompt(){
  var c=getCfg();
  var saved=String(c.toolsAgentCorePrompt||'').trim();
  var version=String(c.toolsAgentCorePromptVersion||'').trim();
  if(!saved || version!==TOOLS_AGENT_CORE_PROMPT_VERSION){
    c.toolsAgentCorePrompt=_toolsAgentCoreDefaultPrompt();
    c.toolsAgentCorePromptVersion=TOOLS_AGENT_CORE_PROMPT_VERSION;
    saveCfg(c);
    return c.toolsAgentCorePrompt;
  }
  return saved;
}
function _toolsSaveAgentCorePrompt(text){
  var c=getCfg();
  c.toolsAgentCorePrompt=String(text||'').trim();
  c.toolsAgentCorePromptVersion=TOOLS_AGENT_CORE_PROMPT_VERSION;
  saveCfg(c);
}
function _ajwAgentSafeArr(v){
  return Array.isArray(v)?v:[];
}
function _ajwAgentSafeNum(v){
  var n=Number(v);
  return isFinite(n)?n:0;
}
function _ajwAgentRecent(rows, picker, limit){
  return _ajwAgentSafeArr(rows).slice(0, limit||3).map(function(item){
    try{ return picker(item)||''; }catch(e){ return ''; }
  }).filter(Boolean);
}
function _ajwAgentTopBy(rows, picker){
  var map={};
  _ajwAgentSafeArr(rows).forEach(function(item){
    var k=String(picker(item)||'').trim();
    if(!k) return;
    map[k]=(map[k]||0)+1;
  });
  var best='-';
  var bestVal=0;
  Object.keys(map).forEach(function(k){
    if(map[k]>bestVal){ best=k; bestVal=map[k]; }
  });
  return {label:best,count:bestVal};
}
