/* ====== EXPORT/IMPORT ====== */
var AJW_BACKUP_VERSION='ajw-full-backup-v3';
function _ajwKeyLooksSensitive(k){
  var key=String(k||'').toLowerCase();
  if(!key) return false;
  if(/(password|secret|token|apikey|api_key|privatekey|private_key|bearer|session)/.test(key)) return true;
  if(/(^|_)(key|auth)(_|$)/.test(key) && !/(monkey|keyboard|keynote)/.test(key)) return true;
  return false;
}
function _ajwSanitizeAny(v, parentKey){
  if(v==null) return v;
  if(Array.isArray(v)) return v.map(function(x){ return _ajwSanitizeAny(x, parentKey); });
  if(typeof v==='object'){
    var out={};
    Object.keys(v).forEach(function(k){
      if(_ajwKeyLooksSensitive(k)){
        out[k]='[REDACTED_SECURE_CORE]';
      }else{
        out[k]=_ajwSanitizeAny(v[k], k);
      }
    });
    return out;
  }
  if(_ajwKeyLooksSensitive(parentKey)) return '[REDACTED_SECURE_CORE]';
  return v;
}
function _ajwSanitizeStorageEntry(key, entry, includeSecrets){
  if(includeSecrets) return entry;
  if(key==='ajw_session') return null;
  if(key==='ajw_cfg'){
    if(entry && entry.mode==='json') return {mode:'json', value:_ajwSanitizeAny(entry.value||{}, 'ajw_cfg')};
    if(entry && entry.mode==='raw'){
      try{ return {mode:'json', value:_ajwSanitizeAny(JSON.parse(entry.value||'{}'), 'ajw_cfg')}; }
      catch(e){ return {mode:'raw', value:'[REDACTED_SECURE_CORE]'}; }
    }
  }
  return entry;
}
function _ajwSafeSet(key,val){
  try{ localStorage.setItem(key, JSON.stringify(val)); }catch(e){}
}
function _ajwFlushRuntimeToLocal(){
  try{ if(typeof saveCfg==='function') saveCfg(getCfg()||{}); }catch(e){}
  try{ if(typeof evalHistory!=='undefined') _ajwSafeSet('ajw_eval', evalHistory||[]); }catch(e){}
  try{ if(typeof payHistory!=='undefined') _ajwSafeSet('ajw_pay', payHistory||[]); }catch(e){}
  try{ if(typeof employees!=='undefined') _ajwSafeSet('ajw_emp', employees||[]); }catch(e){}
  try{ if(typeof customTabs!=='undefined') _ajwSafeSet('ajw_tabs', customTabs||[]); }catch(e){}
  try{ if(typeof kpiData!=='undefined') _ajwSafeSet('ajw_kpi', kpiData||[]); }catch(e){}
  try{ if(typeof supplierHutang!=='undefined') _ajwSafeSet('ajw_supplier', supplierHutang||[]); }catch(e){}
  try{ if(typeof supplierData!=='undefined') _ajwSafeSet('ajw_sup_data', supplierData||[]); }catch(e){}
  try{ if(typeof pesananData!=='undefined') _ajwSafeSet('ajw_pesanan', pesananData||[]); }catch(e){}
  try{ if(typeof _lb!=='undefined') _ajwSafeSet('ajw_laporan', _lb||[]); }catch(e){}
  try{ if(typeof _profitData!=='undefined') _ajwSafeSet('ajw_profit', _profitData||[]); }catch(e){}
  try{ if(typeof _devHub!=='undefined') _ajwSafeSet('ajw_dev_hub', _devHub||{}); }catch(e){}
  try{ if(typeof _hrSops!=='undefined') _ajwSafeSet('ajw_hr_sops', _hrSops||[]); }catch(e){}
  try{ if(typeof _hrControlData!=='undefined') _ajwSafeSet('ajw_hr_control', _hrControlData||{}); }catch(e){}
  try{ if(typeof _toolRefunds!=='undefined') _ajwSafeSet('ajw_tools_refunds', _toolRefunds||[]); }catch(e){}
  try{ if(typeof _toolComplaints!=='undefined') _ajwSafeSet('ajw_tools_complaints', _toolComplaints||[]); }catch(e){}
  try{ if(typeof _toolRequests!=='undefined') _ajwSafeSet('ajw_tools_requests', _toolRequests||[]); }catch(e){}
  try{ if(typeof _toolMaterialStock!=='undefined') _ajwSafeSet('ajw_tools_material_stock', _toolMaterialStock||[]); }catch(e){}
  try{ if(typeof _toolProductRows!=='undefined') _ajwSafeSet('ajw_tools_product_rows', _toolProductRows||[]); }catch(e){}
  try{ if(typeof _finIncome!=='undefined') _ajwSafeSet('ajw_fin_income', _finIncome||[]); }catch(e){}
  try{ if(typeof _finExpense!=='undefined') _ajwSafeSet('ajw_fin_expense', _finExpense||[]); }catch(e){}
  try{ if(typeof _finAssets!=='undefined') _ajwSafeSet('ajw_fin_assets', _finAssets||[]); }catch(e){}
  try{ if(typeof _finSubscriptions!=='undefined') _ajwSafeSet('ajw_fin_subscriptions', _finSubscriptions||[]); }catch(e){}
  try{ if(typeof _finMonthlySettings!=='undefined') _ajwSafeSet('ajw_fin_monthly_settings', _finMonthlySettings||{}); }catch(e){}
  try{ if(typeof _finExpenseCategories!=='undefined') _ajwSafeSet('ajw_fin_expense_categories', _finExpenseCategories||[]); }catch(e){}
  try{ if(typeof _finExpenseTargets!=='undefined') _ajwSafeSet('ajw_fin_expense_targets', _finExpenseTargets||{}); }catch(e){}
  try{ if(typeof _analyticsData!=='undefined') _ajwSafeSet('ajw_analytics_data', _analyticsData||{}); }catch(e){}
  try{ if(typeof _analyticsPurchase!=='undefined') _ajwSafeSet('ajw_analytics_purchase_map', _analyticsPurchase||{}); }catch(e){}
}
function _ajwCollectStorageSnapshot(opts){
  opts=opts||{};
  _ajwFlushRuntimeToLocal();
  var storage={}, keys=[], totalBytes=0;
  for(var i=0;i<localStorage.length;i++){
    var k=localStorage.key(i);
    if(String(k||'').indexOf('ajw_')!==0) continue;
    if(!opts.includeSecrets && k==='ajw_session') continue;
    keys.push(k);
  }
  keys.sort();
  keys.forEach(function(k){
    try{
      var raw=localStorage.getItem(k);
      var entry=null;
      try{ entry={mode:'json',value:JSON.parse(raw)}; }
      catch(e){ entry={mode:'raw',value:raw}; }
      entry=_ajwSanitizeStorageEntry(k, entry, !!opts.includeSecrets);
      if(entry==null) return;
      totalBytes += JSON.stringify(entry).length;
      storage[k]=entry;
    }catch(err){}
  });
  return {storage:storage,keys:keys,totalBytes:totalBytes};
}
function _ajwBuildBackupPayload(opts){
  opts=opts||{};
  var pack=_ajwCollectStorageSnapshot(opts);
  return {
    format:AJW_BACKUP_VERSION,
    exportedAt:(typeof isoNow==='function'?isoNow():new Date().toISOString()),
    app:'AJW',
    timezone:(Intl.DateTimeFormat().resolvedOptions().timeZone||'Asia/Jakarta'),
    summary:{keys:pack.keys.length,totalBytes:pack.totalBytes},
    security:{
      secretsIncluded:!!opts.includeSecrets,
      sessionExcluded:!opts.includeSecrets,
      mode:opts.includeSecrets?'trusted-full':'safe-default'
    },
    storage:pack.storage
  };
}
function exportData(){
  try{
    var payload=_ajwBuildBackupPayload();
    var blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'});
    var a=document.createElement('a');
    a.href=URL.createObjectURL(blob);
    a.download='AJW_Backup_Full_'+ymd()+'_'+String(new Date().getHours()).padStart(2,'0')+String(new Date().getMinutes()).padStart(2,'0')+'.json';
    a.click();
    toast('Backup lokal aman berhasil diexport ('+payload.summary.keys+' key AJW, secret disamarkan)','success',4600);
  }catch(e){ toast('Gagal export backup lokal: '+e.message,'error',5200); }
}
function exportDataTrusted(){
  try{
    var payload=_ajwBuildBackupPayload({includeSecrets:true});
    var blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'});
    var a=document.createElement('a');
    a.href=URL.createObjectURL(blob);
    a.download='AJW_Backup_Internal_'+ymd()+'_'+String(new Date().getHours()).padStart(2,'0')+String(new Date().getMinutes()).padStart(2,'0')+'.json';
    a.click();
    toast('Backup internal penuh diexport. Simpan sangat aman, karena secret ikut terbawa.','warn',5600);
  }catch(e){ toast('Gagal export backup internal: '+e.message,'error',5200); }
}
function _ajwApplyLegacyBackup(d){
  if(d.evalHistory) _ajwSafeSet('ajw_eval', d.evalHistory);
  if(d.payHistory) _ajwSafeSet('ajw_pay', d.payHistory);
  if(d.employees) _ajwSafeSet('ajw_emp', d.employees);
  if(d.customTabs) _ajwSafeSet('ajw_tabs', d.customTabs);
  if(d.kpiData) _ajwSafeSet('ajw_kpi', d.kpiData);
  if(d.supplierHutang) _ajwSafeSet('ajw_supplier', d.supplierHutang);
  if(d.supplierData) _ajwSafeSet('ajw_sup_data', d.supplierData);
  if(d.pesananData) _ajwSafeSet('ajw_pesanan', d.pesananData);
  if(d.hrSops) _ajwSafeSet('ajw_hr_sops', d.hrSops);
  if(d.hrControl) _ajwSafeSet('ajw_hr_control', d.hrControl);
  if(d.devHub) _ajwSafeSet('ajw_dev_hub', d.devHub);
  if(d.cfg||d.config) _ajwSafeSet('ajw_cfg', d.cfg||d.config);
}
function _ajwRestoreFromPayload(payload){
  if(payload && payload.storage && typeof payload.storage==='object'){
    for(var i=localStorage.length-1;i>=0;i--){
      var k=localStorage.key(i);
      if(String(k||'').indexOf('ajw_')===0) localStorage.removeItem(k);
    }
    Object.keys(payload.storage).forEach(function(k){
      var entry=payload.storage[k];
      if(entry && typeof entry==='object' && entry.mode){
        localStorage.setItem(k, entry.mode==='raw'?String(entry.value||''):JSON.stringify(entry.value));
      }else{
        localStorage.setItem(k, JSON.stringify(entry));
      }
    });
    return Object.keys(payload.storage).length;
  }
  _ajwApplyLegacyBackup(payload||{});
  return Object.keys(payload||{}).length;
}
function importData(){
  var inp=document.createElement('input');
  inp.type='file';
  inp.accept='.json';
  inp.onchange=function(e){
    var file=e.target.files&&e.target.files[0];
    if(!file) return;
    var fr=new FileReader();
    fr.onload=function(ev){
      try{
        var d=JSON.parse(ev.target.result);
        var count=_ajwRestoreFromPayload(d);
        toast('Backup berhasil diimport. Memuat ulang sistem AJW...','success',3200);
        setTimeout(function(){ location.reload(); }, 700);
      }catch(err){
        toast('File backup tidak valid atau rusak','error',5200);
      }
    };
    fr.readAsText(file);
  };
  inp.click();
}

