function _toolsWebhookResolvePayload(job, webhook){
  var tpl=String((webhook&&webhook.payloadTemplate)||_toolsWebhookPayloadTemplate());
  var map={
    '{{message}}':String(job.message||''),
    '{{timestamp}}':isoNow(),
    '{{receiver}}':String(job.receiver||''),
    '{{name}}':String(job.name||''),
    '{{media_url}}':String(job.mediaUrl||'')
  };
  Object.keys(map).forEach(function(k){ tpl=tpl.split(k).join(map[k]); });
  try{ return JSON.parse(tpl); }catch(e){ return {raw:tpl}; }
}
