function _toolsAutomationSaveJob(){
  var job={
    id:_toolAutomationEditId||('auto_'+Date.now()),
    name:_toolsInput('TOOL-AUTO-NAME'),
    channel:_toolsInput('TOOL-AUTO-CHANNEL')||'moonwa',
    receiver:_toolsInput('TOOL-AUTO-GROUP'),
    message:_toolsTextarea('TOOL-AUTO-MSG'),
    mediaUrl:_toolsInput('TOOL-AUTO-MEDIA'),
    webhookId:_toolsInput('TOOL-AUTO-WEBHOOK'),
    scheduleType:_toolsInput('TOOL-AUTO-TYPE')||'daily',
    runDate:_toolsInput('TOOL-AUTO-DATE'),
    runTime:_toolsInput('TOOL-AUTO-TIME')||'09:00',
    weekday:_toolsInput('TOOL-AUTO-WEEKDAY')||'1',
    everyMinutes:_num(_toolsInput('TOOL-AUTO-MINS')||60),
    notes:_toolsTextarea('TOOL-AUTO-NOTES'),
    active:!!(document.getElementById('TOOL-AUTO-ACTIVE')||{}).checked,
    lastRunAt:'',
    nextRunAt:'',
    updatedAt:isoNow()
  };
  if(!job.name){ toast('Nama automasi wajib diisi','warn'); return; }
  if(job.channel==='moonwa' && !job.receiver){ toast('Pilih tujuan WhatsApp','warn'); return; }
  if(job.channel==='webhook' && !job.webhookId){ toast('Pilih webhook tujuan','warn'); return; }
  if(job.channel==='agent' && !_toolAgentBridge.endpoint){ toast('Simpan endpoint Agent AI dulu di panel bridge','warn'); return; }
  job.nextRunAt=job.active?_toolsAutomationNextRun(job,new Date()):'';
  var idx=(_toolAutomationJobs||[]).findIndex(function(j){ return j.id===job.id; });
  if(idx>=0){
    job.lastRunAt=_toolAutomationJobs[idx].lastRunAt||'';
    if(!job.nextRunAt) job.nextRunAt=_toolsAutomationNextRun(job,new Date());
    _toolAutomationJobs[idx]=job;
  }else{
    _toolAutomationJobs.unshift(job);
  }
  _toolsSave();
  _toolsAutomationEnsureRunner();
  _toolAutomationEditId='';
  toast('Automation disimpan','success');
  _renderTools('automation');
}
