function _toolsMoonWASend(receiver, text, mediaUrl){
  var wa=_toolsWhatsAppCfg();
  if(!wa.active) return Promise.reject(new Error('Integrasi WhatsApp belum aktif di Admin'));
  if(wa.provider!=='moonwa') return Promise.reject(new Error('Provider WhatsApp aktif saat ini belum didukung untuk pengiriman otomatis'));
  var apiKey=wa.apiKey;
  if(!apiKey) return Promise.reject(new Error('Moon WA API Key belum tersedia'));
  receiver=_toolsBlastNormalizePhone(receiver);
  if(!receiver) return Promise.reject(new Error('Receiver WhatsApp tidak valid'));
  var cleanMedia=String(mediaUrl||'').trim();
  var hasMedia=!!cleanMedia;
  if(hasMedia && !/^https?:\/\//i.test(cleanMedia)) return Promise.reject(new Error('URL gambar harus berupa link publik http/https'));
  var endpoint=hasMedia?wa.mediaEndpoint:wa.messageEndpoint;
  var body=hasMedia?{
    api_key:apiKey,
    receiver:String(receiver||'').trim(),
    data:{url:cleanMedia, media_type:'image', caption:String(text||'').trim()}
  }:{
    api_key:apiKey,
    receiver:String(receiver||'').trim(),
    data:{message:String(text||'').trim()}
  };
  return fetch(endpoint,{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify(body)
  }).then(function(res){
    return res.json().catch(function(){ return {status:false,message:'HTTP '+res.status}; }).then(function(data){
      if(!res.ok || data.error || data.status===false) throw new Error((data&& (data.message||data.msg||data.error)) || ('HTTP '+res.status));
      return {ok:true,data:data,mode:hasMedia?'media':'text'};
    });
  });
}
function _toolsAutomationExecute(job){
  if(!job) return Promise.resolve();
  if(job.channel==='webhook'){
    var webhook=(_toolWebhookDefs||[]).filter(function(w){ return w.id===job.webhookId; })[0];
    if(!webhook || !webhook.url) return Promise.reject(new Error('Webhook tujuan belum valid'));
    return fetch(webhook.url,{
      method:webhook.method||'POST',
      headers:Object.assign({'Content-Type':'application/json'}, webhook.secret?{'x-ajw-secret':webhook.secret}:{}),
      body:JSON.stringify(_toolsWebhookResolvePayload(job, webhook))
    }).then(function(res){
      if(!res.ok) throw new Error('HTTP '+res.status);
      return {ok:true,mode:'webhook'};
    });
  }
  if(job.channel==='agent'){
    if(!_toolAgentBridge.endpoint) return Promise.reject(new Error('Endpoint Agent AI belum diisi'));
    return _toolsAgentBridgeCall('automation_task', job.message, {
      mode:'automation',
      notes:job.notes||'',
      schedule:{type:job.scheduleType, next_run_at:job.nextRunAt},
      name:job.name
    }).then(function(data){
      return {ok:true,mode:'agent',data:data};
    });
  }
  return _toolsMoonWASend(job.receiver, job.message, job.mediaUrl);
}
function _toolsAutomationRunNow(id){
  var job=(_toolAutomationJobs||[]).filter(function(j){ return j.id===id; })[0];
  if(!job){ toast('Automation tidak ditemukan','error'); return; }
  toast('Menjalankan automation...','info');
  _toolsAutomationExecute(job).then(function(res){
    job.lastRunAt=isoNow();
    job.nextRunAt=job.active?_toolsAutomationNextRun(job,new Date()):'';
    if(job.scheduleType==='once') job.active=false;
    _toolsSave();
    _toolsAutomationLog('success',job.name,'Eksekusi manual '+(res.mode||job.channel)+' berhasil');
    toast('Automation berhasil dijalankan','success');
    _renderTools('automation');
  }).catch(function(e){
    _toolsAutomationLog('error',job.name,e.message);
    toast('Automation gagal: '+e.message,'error');
  });
}
function _toolsAutomationTick(){
  if(window._toolsAutomationRunning) return;
  var due=(_toolAutomationJobs||[]).filter(function(job){
    if(!job || !job.active || !job.nextRunAt) return false;
    var d=new Date(job.nextRunAt);
    return !isNaN(d.getTime()) && d.getTime()<=Date.now();
  }).sort(function(a,b){ return String(a.nextRunAt).localeCompare(String(b.nextRunAt)); })[0];
  if(!due) return;
  window._toolsAutomationRunning=true;
  _toolsAutomationExecute(due).then(function(res){
    due.lastRunAt=isoNow();
    if(due.scheduleType==='once'){ due.active=false; due.nextRunAt=''; }
    else due.nextRunAt=_toolsAutomationNextRun(due,new Date());
    due.updatedAt=isoNow();
    _toolsSave();
    _toolsAutomationLog('success',due.name,'Auto-run '+(res.mode||due.channel)+' berhasil');
    if(window._toolsSub==='automation') _renderTools('automation');
  }).catch(function(e){
    due.lastError=e.message;
    due.nextRunAt=_toolsAutomationNextRun(due,new Date());
    _toolsSave();
    _toolsAutomationLog('error',due.name,e.message);
    if(window._toolsSub==='automation') _renderTools('automation');
  }).finally(function(){
    window._toolsAutomationRunning=false;
  });
}
function _toolsAutomationEnsureRunner(){
  if(window._toolsAutomationTimer) return;
  window._toolsAutomationTimer=setInterval(_toolsAutomationTick, 30000);
  setTimeout(_toolsAutomationTick, 5000);
}
