function _toolsDescNormalizeRow(r, idx){
  var code=String(r['kode produk']||r['Kode Produk']||r.kode_produk||r.kode||r['kode']||'').trim();
  var name=String(r['nama produk']||r['Nama Produk']||r.nama_produk||r.nama||r['nama']||'').trim();
  var oldDesc=String(r['deskripsi produk']||r['deskprisi produk']||r['Deskripsi Produk']||r.deskripsi_produk||r.deskripsi||r['deskripsi']||'').trim();
  if(!code && !name && !oldDesc) return null;
  return {
    id:'desc_'+Date.now()+'_'+idx+'_'+Math.random().toString(36).slice(2,6),
    productCode:code,
    productName:name,
    oldDescription:oldDesc,
    newDescription:'',
    status:'ready',
    updatedAt:isoNow(),
    error:''
  };
}
function _toolsDescParseCSV(text){
  var rows=[], row=[], cur='', inQuotes=false;
  text=String(text||'').replace(/^\uFEFF/,'');
  for(var i=0;i<text.length;i++){
    var ch=text[i], next=text[i+1];
    if(ch==='"'){
      if(inQuotes && next==='"'){ cur+='"'; i++; }
      else inQuotes=!inQuotes;
      continue;
    }
    if(ch===',' && !inQuotes){ row.push(cur); cur=''; continue; }
    if((ch==='\n' || ch==='\r') && !inQuotes){
      if(ch==='\r' && next==='\n') i++;
      row.push(cur); rows.push(row); row=[]; cur='';
      continue;
    }
    cur+=ch;
  }
  if(cur!=='' || row.length){ row.push(cur); rows.push(row); }
  if(!rows.length) return [];
  var headers=rows[0].map(function(h){ return String(h||'').trim(); });
  return rows.slice(1).filter(function(cols){
    return cols.some(function(v){ return String(v||'').trim()!==''; });
  }).map(function(cols){
    var obj={};
    headers.forEach(function(h,idx){ obj[h]=cols[idx]==null?'':String(cols[idx]); });
    return obj;
  });
}
