function _toolsDescImportFile(){
  var inp=document.createElement('input');
  inp.type='file';
  inp.accept='.csv,.xlsx,.xls';
  inp.onchange=function(){
    var file=inp.files&&inp.files[0];
    if(!file) return;
    _toolsDescEnsureXLSX(function(ok){
      var name=String(file.name||'').toLowerCase();
      if(ok){
        var fr=new FileReader();
        fr.onload=function(ev){
          try{
            var wb=window.XLSX.read(ev.target.result,{type:'array',cellText:true,cellDates:true});
            var ws=wb.Sheets[wb.SheetNames[0]];
            var rows=window.XLSX.utils.sheet_to_json(ws,{defval:'',raw:false});
            _toolsDescImportRows(rows, file.name);
          }catch(e){ toast('Gagal membaca file spreadsheet: '+e.message,'error',5200); }
        };
        fr.readAsArrayBuffer(file);
        return;
      }
      if(!(name.endsWith('.csv')||name.endsWith('.txt'))){
        toast('Library XLSX gagal dimuat. Gunakan CSV atau cek koneksi browser.','error',5000);
        return;
      }
      var fr2=new FileReader();
      fr2.onload=function(ev){
        try{
          var text=String(ev.target.result||'');
          var rows=_toolsDescParseCSV(text);
          if(!rows.length){ toast('File CSV kosong atau header tidak cocok','error'); return; }
          _toolsDescImportRows(rows, file.name);
        }catch(e){ toast('Gagal membaca CSV: '+e.message,'error'); }
      };
      fr2.readAsText(file);
    });
  };
  inp.click();
}
