function _toolsDescGenerateOne(id, quiet){
  var row=(_toolDescRows||[]).filter(function(r){ return r.id===id; })[0];
  if(!row){ if(!quiet) toast('Baris tidak ditemukan','error'); return Promise.reject(new Error('row not found')); }
  var cfg=getCfg(), key=cfg.openaiKey||'', model=cfg.openaiModel||'gpt-4o-mini';
  if(!key){ if(!quiet) toast('OpenAI API Key belum diset di Admin → Integrasi & API.','error'); return Promise.reject(new Error('no key')); }
  row.status='running'; row.error=''; row.updatedAt=isoNow(); _toolsSave(); if(window._toolsSub==='desc') _renderTools('desc');
  return fetch('https://api.openai.com/v1/chat/completions',{
    method:'POST',
    headers:{'Content-Type':'application/json','Authorization':'Bearer '+key},
    body:JSON.stringify({
      model:model,
      temperature:0.4,
      max_tokens:1200,
      messages:[
        {role:'system',content:'Anda adalah editor deskripsi produk marketplace AJW. Fokus pada perapihan deskripsi dan jangan menambah data yang tidak ada.'},
        {role:'user',content:_toolsDescBuildPrompt(row)}
      ]
    })
  }).then(function(res){
    return res.json().then(function(data){
      if(!res.ok) throw new Error((data&&data.error&&data.error.message)||('HTTP '+res.status));
      var text=String((((data||{}).choices||[])[0]||{}).message&&(((data||{}).choices||[])[0]||{}).message.content||'').trim();
      if(!text) throw new Error('AI tidak mengembalikan deskripsi');
      row.newDescription=text;
      row.status='done';
      row.error='';
      row.updatedAt=isoNow();
      _toolsSave();
      if(!quiet) toast('Deskripsi berhasil direvisi','success');
      if(window._toolsSub==='desc') _renderTools('desc');
      return text;
    });
  }).catch(function(e){
    row.status='error';
    row.error=e.message||String(e);
    row.updatedAt=isoNow();
    _toolsSave();
    if(!quiet) toast('Generate gagal: '+row.error,'error',5200);
    if(window._toolsSub==='desc') _renderTools('desc');
    throw e;
  });
}
function _toolsDescRunFrom(index){
  if(_toolDescRunState.running){ toast('Generate masih berjalan','warn'); return; }
  var rows=_toolDescRows||[];
  if(!rows.length){ toast('Import data deskripsi dulu','warn'); return; }
  _toolDescRunState={running:true,startIndex:index||0};
  var i=index||0;
  function step(){
    if(i>=rows.length){
      _toolDescRunState.running=false;
      _toolsSave();
      toast('Generate deskripsi selesai sampai baris terakhir','success',4200);
      _renderTools('desc');
      return;
    }
    var row=rows[i];
    if(!row){ i++; return step(); }
    _toolsDescGenerateOne(row.id,true).finally(function(){
      i+=1;
      setTimeout(step, 350);
    });
  }
  step();
}
