  var html='<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px"><div><div style="font-size:12px;font-weight:800;color:#fff;margin-bottom:8px">Deskripsi Asli</div><textarea id="TOOL-DESC-EDIT-OLD" class="fi" rows="18" oninput="_toolsDescSetField(\''+id+'\',\'oldDescription\')">'+esc(row.oldDescription||'')+'</textarea></div><div><div style="font-size:12px;font-weight:800;color:#fff;margin-bottom:8px">Deskripsi Terbaru</div><textarea id="TOOL-DESC-EDIT-NEW" class="fi" rows="18" oninput="_toolsDescSetField(\''+id+'\',\'newDescription\')">'+esc(row.newDescription||'')+'</textarea></div></div>';
