  if(!recipients.length){ toast('Pilih minimal satu nomor tujuan marketing','warn'); return; }
  var message=String(_toolsVal('TOOL-BLAST-MARKETING-MESSAGE')||'').trim();
  var imageUrl=String(_toolsVal('TOOL-BLAST-MARKETING-IMAGE')||'').trim();
  var hasTemplate=!!String(_toolsBlastMarketingTemplateValue()||'').trim();
  if(!message && !hasTemplate && !imageUrl){ toast('Isi pesan, template, atau gambar marketing dulu','warn'); return; }
  var kind=String(_toolsVal('TOOL-BLAST-MARKETING-SCH-KIND')||'weekly');
  var job={
    id:_toolBlastMarketingEditId||('blastmkt_'+Date.now()+'_'+Math.random().toString(36).slice(2,6)),
    name:String(_toolsVal('TOOL-BLAST-MARKETING-SCH-NAME')||'Blast Marketing').trim()||'Blast Marketing',
    kind:kind,
    time:String(_toolsVal('TOOL-BLAST-MARKETING-SCH-TIME')||'09:00'),
    weekday:String(_toolsVal('TOOL-BLAST-MARKETING-SCH-WEEKDAY')||'mon'),
    monthday:String(_toolsVal('TOOL-BLAST-MARKETING-SCH-MONTHDAY')||'1'),
    date:String(_toolsVal('TOOL-BLAST-MARKETING-SCH-DATE')||''),
    imageUrl:imageUrl,
    message:message,
    template:_toolsBlastMarketingTemplateValue(),
    recipients:recipients,
    active:true,
    updatedAt:isoNow()
  };
  job.nextRunAt=_toolsBlastMarketingNextRun(job,new Date());
  var idx=(_toolBlastMarketingSchedules||[]).findIndex(function(it){ return it.id===job.id; });
  if(idx>=0) _toolBlastMarketingSchedules[idx]=job; else _toolBlastMarketingSchedules.unshift(job);
