function _toolsBlastMarketingRunNow(id){
  var job=(_toolBlastMarketingSchedules||[]).filter(function(it){ return it.id===id; })[0];
  if(!job) return;
  var recipients=(job.recipients||[]).map(function(phone){ return (_toolBlastPhoneDb||[]).filter(function(it){ return it.phone===phone; })[0]; }).filter(Boolean);
  if(!recipients.length){ toast('Tidak ada penerima valid pada jadwal ini','warn'); return; }
  if(_toolBlastSending){ toast('Blast sedang berjalan','warn'); return; }
  _toolBlastSending=true;
  _toolBlastMarketingProgress={running:true,total:recipients.length,done:0,success:0,error:0,current:'',logs:[]};
  var i=0, delayMs=_toolsBlastDelayValue();
  if(window._toolsSub==='blastmkt') _renderTools('blastmkt');
  function step(){
    if(i>=recipients.length){
      _toolBlastSending=false;
      _toolBlastMarketingProgress.running=false;
      job.lastRunAt=isoNow();
      job.nextRunAt=job.active?_toolsBlastMarketingNextRun(job,new Date()):'';
      _toolsSave();
      if(window._toolsSub==='blastmkt') _renderTools('blastmkt');
      return;
    }
    var item=recipients[i];
    _toolBlastMarketingProgress.current=item.receiverName||item.phoneRaw||item.phone||'-';
    var payload=_toolsBlastBuildMarketingMessage(item, job.message);
    _toolsMoonWASend(item.phone, payload, job.imageUrl).then(function(){
      item.lastMarketingAt=isoNow();
      item.lastMarketingError='';
      item.marketingBlastCount=Number(item.marketingBlastCount||0)+1;
      item.totalBlastCount=Number(item.totalBlastCount||0)+1;
      _toolBlastMarketingProgress.success+=1;
      _toolBlastMarketingProgress.logs.unshift({status:'success',target:item.phoneRaw||item.phone,name:item.receiverName||'-',message:'Terkirim',ts:isoNow()});
    }).catch(function(e){
      item.lastMarketingError=e.message||String(e);
      _toolBlastMarketingProgress.error+=1;
      _toolBlastMarketingProgress.logs.unshift({status:'error',target:item.phoneRaw||item.phone,name:item.receiverName||'-',message:item.lastMarketingError,ts:isoNow()});
    }).finally(function(){
      _toolBlastMarketingProgress.done+=1;
      _toolsSave();
      i+=1;
      if(window._toolsSub==='blastmkt') _renderTools('blastmkt');
      setTimeout(step, delayMs);
    });
  }
  step();
}
function _toolsBlastMarketingTick(){
  if(window._toolsBlastMarketingRunning || _toolBlastSending) return;
  var due=(_toolBlastMarketingSchedules||[]).filter(function(job){
    if(!job || !job.active || !job.nextRunAt) return false;
    var d=new Date(job.nextRunAt);
    return !isNaN(d.getTime()) && d.getTime()<=Date.now();
  }).sort(function(a,b){ return String(a.nextRunAt).localeCompare(String(b.nextRunAt)); })[0];
  if(!due) return;
  window._toolsBlastMarketingRunning=true;
  var recipients=(due.recipients||[]).map(function(phone){ return (_toolBlastPhoneDb||[]).filter(function(it){ return it.phone===phone; })[0]; }).filter(Boolean);
  _toolBlastMarketingProgress={running:true,total:recipients.length,done:0,success:0,error:0,current:'',logs:[]};
  var i=0, delayMs=_toolsBlastDelayValue();
  function step(){
    if(i>=recipients.length){
      due.lastRunAt=isoNow();
      due.nextRunAt=due.active?_toolsBlastMarketingNextRun(due,new Date()):'';
      _toolsSave();
      _toolBlastMarketingProgress.running=false;
      window._toolsBlastMarketingRunning=false;
      return;
    }
    var item=recipients[i];
    _toolBlastMarketingProgress.current=item.receiverName||item.phoneRaw||item.phone||'-';
    var payload=_toolsBlastBuildMarketingMessage(item, due.message);
    _toolsMoonWASend(item.phone, payload, due.imageUrl).then(function(){
      item.lastMarketingAt=isoNow();
      item.lastMarketingError='';
      item.marketingBlastCount=Number(item.marketingBlastCount||0)+1;
      item.totalBlastCount=Number(item.totalBlastCount||0)+1;
      _toolBlastMarketingProgress.success+=1;
      _toolBlastMarketingProgress.logs.unshift({status:'success',target:item.phoneRaw||item.phone,name:item.receiverName||'-',message:'Terkirim',ts:isoNow()});
    }).catch(function(e){
      item.lastMarketingError=e.message||String(e);
      _toolBlastMarketingProgress.error+=1;
      _toolBlastMarketingProgress.logs.unshift({status:'error',target:item.phoneRaw||item.phone,name:item.receiverName||'-',message:item.lastMarketingError,ts:isoNow()});
    }).finally(function(){
      _toolBlastMarketingProgress.done+=1;
      _toolsSave();
      i+=1;
      if(window._toolsSub==='blastmkt') _renderTools('blastmkt');
      setTimeout(step, delayMs);
    });
  }
  step();
}
