function _toolsMediaRender(prefix){
  var dataEl=document.getElementById(prefix+'-DATA'), nameEl=document.getElementById(prefix+'-NAME'), preview=document.getElementById(prefix+'-PREVIEW');
  if(!dataEl||!preview) return;
  var data=dataEl.value||'', name=nameEl?(nameEl.value||''):'';
  if(!data){ preview.innerHTML=''; return; }
  preview.innerHTML='<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;padding:8px 10px;background:#050505;border:1px solid rgba(255,255,255,.08);border-radius:12px"><img src="'+data+'" style="width:64px;height:64px;object-fit:cover;border-radius:10px;border:1px solid rgba(255,255,255,.08)"><div style="font-size:11px;color:#D7E1EA;flex:1">Lampiran: '+esc(name||'gambar')+'</div><div style="display:flex;gap:6px"><button class="btnsm" onclick="_toolsOpenMedia(\''+prefix+'\')">Buka</button><button class="btnsm" onclick="_toolsClearMedia(\''+prefix+'\')">Hapus</button></div></div>';
}
function _toolsDataUrlToBlob(dataUrl){
  try{
    var parts=String(dataUrl||'').split(',');
    if(parts.length<2) return null;
    var mime=((parts[0].match(/data:([^;]+)/)||[])[1])||'application/octet-stream';
    var binary=atob(parts[1]);
    var arr=new Uint8Array(binary.length);
    for(var i=0;i<binary.length;i++) arr[i]=binary.charCodeAt(i);
    return new Blob([arr],{type:mime});
  }catch(e){ return null; }
}
function _toolsCopyImageData(dataUrl){
  var blob=_toolsDataUrlToBlob(dataUrl);
  if(!blob){ toast('Gagal membaca gambar untuk disalin','error'); return; }
  if(navigator.clipboard && window.ClipboardItem){
    navigator.clipboard.write([new ClipboardItem({[blob.type]:blob})]).then(function(){
      toast('Gambar disalin ke clipboard','success');
    }).catch(function(e){
      toast('Gagal menyalin gambar: '+e.message,'error');
    });
    return;
  }
  toast('Browser ini belum mendukung copy gambar langsung. Gunakan Unduh atau Buka Gambar.', 'warn', 4200);
}
function _toolsGuessMarketplace(value){
  var raw=String(value||'').trim().toUpperCase();
  if(!raw) return '';
  if(raw.indexOf('SPX')===0) return 'Shopee';
  if(raw.indexOf('LXAD')===0 || raw.indexOf('JNAP')===0) return 'Lazada';
  if(raw.indexOf('JZ')===0) return 'Tiktok';
  return '';
}
function _toolsSetFieldValue(id,value){
  var el=document.getElementById(id);
  if(!el || !String(value||'').trim()) return;
  el.value=String(value).trim();
}
function _toolsSetMarketplaceByValue(id, raw){
  var el=document.getElementById(id);
  if(!el) return;
  var guessed=_toolsGuessMarketplace(raw)||String(raw||'').trim();
  if(!guessed) return;
  var found=false;
  Array.prototype.slice.call(el.options||[]).forEach(function(opt){
    if(String(opt.value||'').toLowerCase()===String(guessed).toLowerCase()) found=true;
  });
  if(found) el.value=guessed;
}
function _toolsExtractLabelValue(text, labels){
  var src=String(text||'');
  for(var i=0;i<labels.length;i++){
    var re=new RegExp(labels[i]+'\\s*:\\s*(.+)','im');
    var m=src.match(re);
    if(m && m[1]) return String(m[1]).trim();
  }
  return '';
}
function _toolsAutofillFromAI(kind,text){
  var body=String(text||'');
  if(!body) return;
  var orderNo=_toolsExtractLabelValue(body,['No Pesanan']);
  var trackingNo=_toolsExtractLabelValue(body,['No Resi','Nomor Resi']);
  var productName=_toolsExtractLabelValue(body,['Produk','Nama Item','Nama','Produk Saat Ini']);
  var marketplace=_toolsExtractLabelValue(body,['Marketplace']);
  if(!marketplace) marketplace=_toolsGuessMarketplace(trackingNo);
  if(kind==='refund'){
    _toolsSetFieldValue('TOOL-RF-ORDER', orderNo);
    _toolsSetFieldValue('TOOL-RF-RESI', trackingNo);
    _toolsSetFieldValue('TOOL-RF-ITEM', productName);
    _toolsSetMarketplaceByValue('TOOL-RF-MARKET', marketplace||trackingNo);
  }else if(kind==='complaint'){
    _toolsSetFieldValue('TOOL-CP-ORDER', orderNo);
    _toolsSetFieldValue('TOOL-CP-RESI', trackingNo);
    _toolsSetFieldValue('TOOL-CP-PRODUCT', productName);
    _toolsSetMarketplaceByValue('TOOL-CP-MARKET', marketplace||trackingNo);
  }else if(kind==='request'){
    _toolsSetFieldValue('TOOL-RQ-ORDER', orderNo);
    _toolsSetFieldValue('TOOL-RQ-RESI', trackingNo);
    _toolsSetFieldValue('TOOL-RQ-PRODUCT', productName);
    _toolsSetMarketplaceByValue('TOOL-RQ-MARKET', marketplace||trackingNo);
  }
}
function _toolsLoadImage(src){
  return new Promise(function(resolve,reject){
    var img=new Image();
    img.onload=function(){ resolve(img); };
    img.onerror=reject;
    img.src=src;
  });
}
function _toolsCanvasToDataURL(canvas, quality){
  try{ return canvas.toDataURL('image/jpeg', quality); }catch(e){ return canvas.toDataURL(); }
}
function _toolsProcessImageFile(file,prefix){
  if(!file) return;
  var reader=new FileReader();
  reader.onload=function(ev){
    var src=String((ev&&ev.target&&ev.target.result)||'');
    _toolsLoadImage(src).then(function(img){
      var maxDim=960;
      var w=img.naturalWidth||img.width||0;
      var h=img.naturalHeight||img.height||0;
      if(!w||!h){ _toolsMediaSet(prefix,src,file.name||'gambar-upload'); return; }
      var scale=Math.min(1,maxDim/Math.max(w,h));
      var canvas=document.createElement('canvas');
      canvas.width=Math.max(1,Math.round(w*scale));
      canvas.height=Math.max(1,Math.round(h*scale));
      var ctx=canvas.getContext('2d');
      ctx.fillStyle='#ffffff';
      ctx.fillRect(0,0,canvas.width,canvas.height);
      ctx.drawImage(img,0,0,canvas.width,canvas.height);
      var quality=0.82;
      var data=_toolsCanvasToDataURL(canvas,quality);
      while(data.length>120000 && quality>0.34){
        quality-=0.08;
        data=_toolsCanvasToDataURL(canvas,quality);
      }
      _toolsMediaSet(prefix,data,(file.name||'gambar-upload').replace(/\.(png|webp|gif)$/i,'.jpg'));
    }).catch(function(){
      _toolsMediaSet(prefix,src,file.name||'gambar-upload');
    });
  };
  reader.readAsDataURL(file);
}
function _toolsMediaSet(prefix,data,name){
  var dataEl=document.getElementById(prefix+'-DATA'), nameEl=document.getElementById(prefix+'-NAME'), pasteEl=document.getElementById(prefix+'-PASTE');
  if(dataEl) dataEl.value=data||'';
  if(nameEl) nameEl.value=name||'';
  if(pasteEl) pasteEl.textContent=data?('Gambar siap: '+(name||'lampiran')):'Paste gambar di sini atau pilih file manual.';
  _toolsMediaRender(prefix);
}
function _toolsMediaFile(input,prefix){
  var file=input&&input.files&&input.files[0];
  if(!file) return;
  _toolsProcessImageFile(file,prefix);
}
function _toolsMediaPaste(event,prefix){
  var items=(event.clipboardData&&event.clipboardData.items)||[];
  for(var i=0;i<items.length;i++){
    if(items[i].type&&items[i].type.indexOf('image/')===0){
      event.preventDefault();
      var file=items[i].getAsFile();
      if(!file) return;
      _toolsProcessImageFile(file,prefix);
      return;
    }
  }
}
function _toolsCollectContext(ids){
  return String(ids||'').split('|').map(function(id){
    var el=document.getElementById(id);
    if(!el) return '';
    var v=String(el.value||el.textContent||'').trim();
    if(!v) return '';
    var label='';
    var p=el.closest?el.closest('div'):null;
    if(p){
      var l=p.querySelector? p.querySelector('label.lbl') : null;
      if(l) label=String(l.textContent||'').trim();
    }
    return (label?label+': ':'')+v;
  }).filter(Boolean).join('\n');
}
function _toolsExtractResponseText(d){
  if(!d) return '';
  if(d.output_text) return String(d.output_text).trim();
  try{
    var texts=[];
    (d.output||[]).forEach(function(o){
      (o.content||[]).forEach(function(c){
        if(c.text) texts.push(c.text);
        else if(c.type==='output_text' && c.text) texts.push(c.text);
      });
    });
    return texts.join('\n').trim();
  }catch(e){}
  return '';
}
function _toolsAnalyzeMedia(prefix,kind,targetId,contextIds){
  var dataEl=document.getElementById(prefix+'-DATA');
  var btn=document.getElementById(prefix+'-AIBTN');
  var outEl=document.getElementById(targetId);
  if(!dataEl||!dataEl.value){ toast('Paste atau upload gambar dulu sebelum memakai AI','warn'); return; }
  var cfg=getCfg();
  var key=cfg.openaiKey||'';
  if(!key){ toast('OpenAI API Key belum diset di Admin → Integrasi & API. Saya tidak hardcode key ke file demi keamanan.','error',5200); return; }
  var contextText=_toolsCollectContext(contextIds);
  var kindLabel=_toolsPromptKindLabel(kind);
  var basePrompt=_toolsGetAIPrompt(kind);
  if(!String(basePrompt||'').trim()){ toast('Prompt AI untuk tab ini kosong. Buka tombol Prompt untuk mengisi atau reset default AJW.','warn',4200); return; }
  var strictInstructions=[
    'Anda adalah AI parser khusus modul Tools AJW.',
    'Anda sedang bekerja untuk tab: '+kindLabel+'.',
    'Gunakan HANYA prompt tab ini sebagai aturan utama.',
    'Jangan pakai format dari tab lain.',
    'Jangan ubah jenis kasus menjadi pengembalian dana jika tab aktif bukan Pengembalian Dana.',
    'Jangan ubah jenis kasus menjadi komplain jika tab aktif bukan Komplain.',
    'Jangan ubah jenis kasus menjadi request jika tab aktif bukan Request.',
    'Output harus mengikuti prompt tab aktif secara ketat.'
  ].join('\n');
  var finalPrompt=[
    'PROMPT TAB '+kindLabel.toUpperCase()+':',
    basePrompt,
    '',
    'KONTEKS FIELD AJW:',
    contextText||'-',
    '',
    'CATATAN:',
    '- Gunakan informasi dari gambar sebagai sumber utama.',
    '- Gunakan konteks field AJW sebagai pelengkap.',
    '- Jangan mencampur format dari tab lain.',
    '- Tanggal sistem AJW: '+ymd()
  ].join('\n');
  if(btn){ btn.disabled=true; btn.textContent='AI...'; }
  if(outEl && !String(outEl.value||'').trim()) outEl.value='Memproses analisa AI...';
  fetch('https://api.openai.com/v1/responses',{
    method:'POST',
    headers:{'Content-Type':'application/json','Authorization':'Bearer '+key},
    body:JSON.stringify({
      model:cfg.openaiModel||'gpt-4.1-mini',
      instructions:strictInstructions,
      input:[{
        role:'user',
        content:[
          {type:'input_text', text:finalPrompt},
          {type:'input_image', image_url:dataEl.value, detail:'auto'}
        ]
      }]
    })
  }).then(function(r){ return r.json(); }).then(function(d){
    var txt=_toolsExtractResponseText(d);
    if(!txt){
      if(outEl) outEl.value='';
      toast('Analisa AI tidak menghasilkan teks. Coba gambar yang lebih jelas.','warn',4200);
      return;
    }
    if(outEl) outEl.value=txt;
    _toolsAutofillFromAI(kind, txt);
    toast('Analisa AI gambar selesai','success',3600);
  }).catch(function(e){
    if(outEl && outEl.value==='Memproses analisa AI...') outEl.value='';
    toast('Gagal analisa AI: '+e.message,'error',5000);
  }).finally(function(){
    if(btn){ btn.disabled=false; btn.textContent='AI'; }
  });
}
function _toolsRunAgentAI(){
  var promptEl=document.getElementById('TOOLS-AGENT-ASK');
  var outEl=document.getElementById('TOOLS-AGENT-OUT');
  var btn=document.getElementById('TOOLS-AGENT-RUN');
  var modeEl=document.getElementById('TOOLS-AGENT-MODE');
  var ask=promptEl?String(promptEl.value||'').trim():'';
  if(!ask){ toast('Isi perintah Agent AI dulu','warn'); return; }
  var mode=modeEl?String(modeEl.value||'analysis').trim():'analysis';
  var cfg=getCfg();
  var finalPrompt=_toolsGetAgentCorePrompt()+'\n\nKonteks sistem AJW:\n'+_toolsAgentContextSummary()+'\n\nTugas user:\n'+ask;
  if(btn){ btn.disabled=true; btn.textContent='Memproses...'; }
  if(outEl) outEl.value='Agent AI sedang memproses...';
  var bridgeStatus=_toolsAgentBridgeStatus();
  var useBridge=bridgeStatus.ready;
  var runner=useBridge
    ? _toolsAgentBridgeCall('agent_run', ask, {mode:mode, notes:'Permintaan manual dari menu AI > Agent AI'})
        .then(function(d){ return _toolsBridgeResponseText(d)||_toolsBridgeResponsePretty(d)||''; })
    : _toolsAgentDirectOpenAIRun(finalPrompt, mode);
  runner.then(function(txt){
    if(!txt){
      if(outEl) outEl.value='';
      toast('Agent AI tidak menghasilkan jawaban. Coba perjelas prompt.', 'warn', 4200);
      return;
    }
    if(outEl) outEl.value=String(txt).trim();
    toast('Agent AI selesai'+(useBridge?' via bridge':' via fallback OpenAI Direct'), 'success', 3200);
  }).catch(function(e){
    if(outEl && outEl.value==='Agent AI sedang memproses...') outEl.value='';
    var msg=String((e&&e.message)||e||'Unknown error');
    if(!useBridge && bridgeStatus.reason && bridgeStatus.reason!=='runtime-direct'){
      msg='Bridge belum siap ('+bridgeStatus.message+'). Fallback OpenAI juga gagal: '+msg;
    }
    toast('Gagal menjalankan Agent AI: '+msg, 'error', 6200);
  }).finally(function(){
    if(btn){ btn.disabled=false; btn.textContent='Jalankan Agent AI'; }
  });
}
function _toolsAgentSubmitCodexTask(){
  var ask=_toolsTextarea('TOOLS-AGENT-ASK');
  var outEl=document.getElementById('TOOLS-AGENT-OUT');
  if(!ask){ toast('Isi tugas Codex dulu di workspace Agent AI','warn'); return; }
  var bridgeStatus=_toolsAgentBridgeStatus();
  if(!bridgeStatus.ready){
    if(outEl) outEl.value='Bridge belum siap untuk task Codex.\n\n'+bridgeStatus.message+'\n\nIsi endpoint API bridge POST JSON yang benar, bukan root dashboard OpenClaw.';
    toast('Bridge Codex belum siap: '+bridgeStatus.message,'warn',6200);
    return;
  }
  if(outEl) outEl.value='Mengirim tugas Codex melalui bridge...';
  _toolsAgentBridgeCall('codex_task', ask, {
    mode:'codex_task',
    codexTask:true,
    notes:'Tugas pengembangan AJW yang dikirim dari Agent AI'
  }).then(function(data){
    var txt=_toolsBridgeResponseText(data)||_toolsBridgeResponsePretty(data)||'Tugas Codex sudah dikirim ke bridge.';
    if(outEl) outEl.value=txt;
    toast('Tugas Codex dikirim ke bridge','success',3200);
  }).catch(function(e){
    if(outEl) outEl.value='';
    toast('Gagal kirim tugas Codex: '+e.message,'error',5200);
  });
}
