  var recentComplaints=periodComplaints.slice(0,8).map(function(r){
    return { title:r.orderNo+' • '+r.issueType, meta:_toolsMoney(r.nominal||0), sub:(r.marketplace||'-')+' • '+(r.tsLabel||'') };
  });
  var recentRequests=periodRequests.slice(0,8).map(function(r){
    return { title:(r.product||r.title||'-'), meta:_toolsGroupNameById(r.groupId)||'Request', sub:(r.marketplace||'-')+' • '+(r.tsLabel||'') };
  });
  var recentBlast=blastHistory.slice(0,8).map(function(r){
    return { title:(r.receiverName||r.buyerName||r.orderNo||'-'), meta:r.status||'ready', sub:(r.marketplace||'-')+' • '+(r.phoneRaw||r.nomorTelepon||'-') };
  });
  var h='';
  h+='<div class="card" style="margin-bottom:12px;background:#090909;border:1px solid rgba(255,255,255,.08)"><div style="display:flex;justify-content:space-between;align-items:flex-start;gap:14px;flex-wrap:wrap"><div><div style="font-size:15px;font-weight:800;color:#fff">Dashboard Tools</div><div style="font-size:11px;color:var(--tx2);margin-top:4px">Rekap refund, komplain, dan request. Filter cepat tersedia untuk 7 hari, 30 hari, atau periode manual.</div></div><div style="display:flex;gap:8px;flex-wrap:wrap"><button class="'+(_toolsRange==='7d'?'btnp':'btns')+'" onclick="_toolsSetRange(\'7d\')">7 Hari</button><button class="'+(_toolsRange==='30d'?'btnp':'btns')+'" onclick="_toolsSetRange(\'30d\')">1 Bulan</button><button class="'+(_toolsRange==='manual'?'btnp':'btns')+'" onclick="_toolsSetRange(\'manual\')">Manual</button></div></div>';
  h+='<div style="display:grid;grid-template-columns:1fr 1fr auto;gap:10px;margin-top:12px;align-items:end"><div><label class="lbl">Dari Tanggal</label><input id="TOOLS-FROM" type="date" class="fi" value="'+esc(_toolsDateFrom||'')+'"></div><div><label class="lbl">Sampai Tanggal</label><input id="TOOLS-TO" type="date" class="fi" value="'+esc(_toolsDateTo||'')+'"></div><div><button class="btnp" onclick="_toolsApplyManualRange()" style="padding:10px 14px">Terapkan Periode</button></div></div>';
  h+='<div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:10px"><span class="chip" style="background:#050505;border:1px solid rgba(240,197,106,.25);color:#F0C56A">Periode: '+esc(_toolsPeriodLabel())+'</span><span class="chip" style="background:#050505;border:1px solid rgba(255,255,255,.09);color:#D7E1EA">Refund 7 hari: '+refund7.length+'</span><span class="chip" style="background:#050505;border:1px solid rgba(255,255,255,.09);color:#D7E1EA">Komplain 7 hari: '+complaint7.length+'</span><span class="chip" style="background:#050505;border:1px solid rgba(255,255,255,.09);color:#D7E1EA">Refund 1 bulan: '+refund30.length+'</span><span class="chip" style="background:#050505;border:1px solid rgba(255,255,255,.09);color:#D7E1EA">Komplain 1 bulan: '+complaint30.length+'</span><span class="chip" style="background:#050505;border:1px solid rgba(255,255,255,.09);color:#D7E1EA">Request 7 hari: '+request7.length+'</span></div></div>';
